const proof = $input.first().json;

if (proof.verified !== true) {
  throw new Error(`Bilig forecast proof did not verify: ${JSON.stringify(proof)}`);
}

if (proof.editedCell !== 'Inputs!B3') {
  throw new Error(`Expected Inputs!B3, received ${proof.editedCell}`);
}

if (!proof.checks?.formulasPersisted || !proof.checks?.restoredMatchesAfter || !proof.checks?.computedOutputChanged) {
  throw new Error(`Formula proof checks failed: ${JSON.stringify(proof.checks)}`);
}

return [
  {
    json: {
      verdict: 'verified',
      operation: 'forecast',
      editedCell: proof.editedCell,
      beforeExpectedArr: proof.before.expectedArr,
      afterExpectedArr: proof.after.expectedArr,
      targetGap: proof.after.targetGap,
      checks: proof.checks
    }
  }
];

const proof = $input.first().json;

if (proof.verified !== true) {
  throw new Error(`Bilig WorkPaper JSON proof did not verify: ${JSON.stringify(proof)}`);
}

const after = proof.readback?.after?.find((cell) => cell.cell === 'Summary!B2');
if (!after || after.displayValue !== '8') {
  throw new Error(`Expected Summary!B2 to recalculate to 8, received ${JSON.stringify(proof.readback?.after)}`);
}

if (!proof.checks?.formulasPersisted || !proof.checks?.restoredMatchesAfter || !proof.checks?.computedOutputChanged) {
  throw new Error(`Formula proof checks failed: ${JSON.stringify(proof.checks)}`);
}

if (proof.updatedDocument?.format !== 'bilig.headless.work-paper.document.v1') {
  throw new Error('Expected updated WorkPaper JSON document in the response');
}

return [
  {
    json: {
      verdict: 'verified',
      operation: 'workpaper-json',
      editedCell: proof.editedCells[0].cell,
      readbackCell: after.cell,
      afterDisplayValue: after.displayValue,
      updatedDocumentFormat: proof.updatedDocument.format,
      checks: proof.checks
    }
  }
];
